-- TABLE WF_APPROVAL_DETAIL

  CREATE TABLE "CMX"."WF_APPROVAL_DETAIL" 
   (	"DETAIL_ID" NUMBER(19,0) NOT NULL ENABLE, 
	"APPROVAL_ID" NUMBER(19,0) NOT NULL ENABLE, 
	"NODE_ID" NUMBER(19,0) NOT NULL ENABLE, 
	"APPROVAL_LEVEL" NUMBER(10,0) NOT NULL ENABLE, 
	"NODE_NAME" VARCHAR2(200), 
	"APPROVAL_MODE" VARCHAR2(20) DEFAULT 'OR' NOT NULL ENABLE, 
	"TARGET_TYPE" VARCHAR2(20) NOT NULL ENABLE, 
	"TARGET_USER_ID" NUMBER(19,0), 
	"TARGET_USER_NAME" VARCHAR2(128), 
	"TARGET_ROLE_ID" NUMBER(19,0), 
	"TARGET_ROLE_CODE" VARCHAR2(64), 
	"TARGET_ROLE_NAME" VARCHAR2(128), 
	"STATUS" VARCHAR2(30) NOT NULL ENABLE, 
	"OPERATE_USER_ID" NUMBER(19,0), 
	"OPERATE_USERNAME" VARCHAR2(64), 
	"OPERATE_REAL_NAME" VARCHAR2(128), 
	"APPROVE_COMMENT" VARCHAR2(1000), 
	"APPROVE_TIME" TIMESTAMP (6), 
	"OPERATE_TIME" TIMESTAMP (6), 
	"CREATE_BY" VARCHAR2(64), 
	"CREATE_TIME" TIMESTAMP (6) DEFAULT SYSTIMESTAMP, 
	"UPDATE_BY" VARCHAR2(64), 
	"UPDATE_TIME" TIMESTAMP (6) DEFAULT SYSTIMESTAMP, 
	"ROUND_NO" NUMBER(10,0) DEFAULT 1 NOT NULL ENABLE, 
	"IS_FORCED" NUMBER(1,0) DEFAULT 0 NOT NULL ENABLE, 
	"AUTO_REASON" VARCHAR2(50), 
	 CONSTRAINT "CK_WF_DETAIL_TARGET_TYPE" CHECK (TARGET_TYPE IN ('USER', 'ROLE')) ENABLE, 
	 CONSTRAINT "CK_WF_DETAIL_MODE" CHECK (APPROVAL_MODE IN ('OR', 'AND')) ENABLE, 
	 CONSTRAINT "PK_WF_APPROVAL_DETAIL" PRIMARY KEY ("DETAIL_ID")
  USING INDEX  ENABLE, 
	 CONSTRAINT "CK_WF_DETAIL_STATUS" CHECK (STATUS IN ('WAITING', 'PENDING', 'APPROVED', 'REJECTED', 'SKIPPED', 'CANCELED', 'AUTO_APPROVED')) ENABLE, 
	 CONSTRAINT "FK_WF_DETAIL_MAIN" FOREIGN KEY ("APPROVAL_ID")
	  REFERENCES "CMX"."WF_APPROVAL_MAIN" ("APPROVAL_ID") ENABLE, 
	 CONSTRAINT "FK_WF_DETAIL_NODE" FOREIGN KEY ("NODE_ID")
	  REFERENCES "CMX"."WF_FLOW_NODE" ("NODE_ID") ENABLE, 
	 CONSTRAINT "FK_WF_DETAIL_USER" FOREIGN KEY ("TARGET_USER_ID")
	  REFERENCES "CMX"."T_COST_USER" ("ID") ENABLE, 
	 CONSTRAINT "FK_WF_DETAIL_ROLE" FOREIGN KEY ("TARGET_ROLE_ID")
	  REFERENCES "CMX"."T_COST_ROLE" ("ID") ENABLE, 
	 CONSTRAINT "FK_WF_DETAIL_OPER_USER" FOREIGN KEY ("OPERATE_USER_ID")
	  REFERENCES "CMX"."T_COST_USER" ("ID") ENABLE
   ) ;
/

