-- TABLE WF_FLOW_APPROVER

  CREATE TABLE "CMX"."WF_FLOW_APPROVER" 
   (	"ID" NUMBER(19,0) NOT NULL ENABLE, 
	"NODE_ID" NUMBER(19,0) NOT NULL ENABLE, 
	"APPLY_DEPT_ID" NUMBER(19,0), 
	"APPLY_DEPT_NAME" VARCHAR2(128), 
	"TARGET_TYPE" VARCHAR2(20) NOT NULL ENABLE, 
	"TARGET_USER_ID" NUMBER(19,0), 
	"TARGET_USER_NAME" VARCHAR2(128), 
	"TARGET_ROLE_ID" NUMBER(19,0), 
	"TARGET_ROLE_CODE" VARCHAR2(64), 
	"TARGET_ROLE_NAME" VARCHAR2(128), 
	"SORT_ORDER" NUMBER(5,0) DEFAULT 0, 
	"IS_ENABLED" NUMBER(1,0) DEFAULT 1 NOT NULL ENABLE, 
	"CREATE_BY" VARCHAR2(64), 
	"CREATE_TIME" TIMESTAMP (6) DEFAULT SYSTIMESTAMP, 
	"UPDATE_BY" VARCHAR2(64), 
	"UPDATE_TIME" TIMESTAMP (6) DEFAULT SYSTIMESTAMP, 
	"CONDITION_MODE" VARCHAR2(20) DEFAULT 'ALWAYS' NOT NULL ENABLE, 
	"LOGIC_TREE" CLOB, 
	"SQL_EXPR" CLOB, 
	"ON_ERROR" VARCHAR2(30) DEFAULT 'REQUIRE_APPROVAL' NOT NULL ENABLE, 
	 CONSTRAINT "CK_WF_APPROVER_TYPE" CHECK (TARGET_TYPE IN ('USER', 'ROLE')) ENABLE, 
	 CONSTRAINT "CK_WF_APPROVER_ENABLED" CHECK (IS_ENABLED IN (0, 1)) ENABLE, 
	 CONSTRAINT "CK_WF_APPROVER_TARGET" CHECK (
    (TARGET_TYPE = 'USER' AND TARGET_USER_ID IS NOT NULL AND TARGET_ROLE_ID IS NULL)
    OR
    (TARGET_TYPE = 'ROLE' AND TARGET_ROLE_ID IS NOT NULL AND TARGET_USER_ID IS NULL)
  ) ENABLE, 
	 CONSTRAINT "PK_WF_FLOW_APPROVER" PRIMARY KEY ("ID")
  USING INDEX  ENABLE, 
	 CONSTRAINT "FK_WF_APPROVER_NODE" FOREIGN KEY ("NODE_ID")
	  REFERENCES "CMX"."WF_FLOW_NODE" ("NODE_ID") ENABLE, 
	 CONSTRAINT "FK_WF_APPROVER_DEPT" FOREIGN KEY ("APPLY_DEPT_ID")
	  REFERENCES "CMX"."T_COST_DEPARTMENT" ("ID") ENABLE, 
	 CONSTRAINT "FK_WF_APPROVER_USER" FOREIGN KEY ("TARGET_USER_ID")
	  REFERENCES "CMX"."T_COST_USER" ("ID") ENABLE, 
	 CONSTRAINT "FK_WF_APPROVER_ROLE" FOREIGN KEY ("TARGET_ROLE_ID")
	  REFERENCES "CMX"."T_COST_ROLE" ("ID") ENABLE
   ) ;
/

